	private		int				pos				= JSS.length;

	/**
	 * コンストラクタ
	 */
	public KSpriteGroupJ34(KPanel panel, String storyParam){

		super(panel);

		if(storyParam != null){

			int intX = Integer.parseInt(storyParam);

			super.setX(intX);

		}

	}

	/**
	 * 実行メソッド
	 */
	public void run(){

		// 一定時間経過の場合、
		if((time % 16) == 0){

			// ポジションを変更
			pos--;

			// 地面データを取得
			int[] js = JSS[pos];

			// スプライト配置
			super.haitiSprite(js);

		} // end if 一定時間経過の場合

		// 全て配置したら、
		if(pos <= 0){
			// スプライトグループを削除
			super.getKPanel().removeSpriteGroup(this);
		}

	} // end run

